// Validate input and guard against skipped/disabled cases.
const asset = $input.first().json;

if (asset._meta_skip) {
  return [{ json: { _publish_skip: true, reason: asset.reason || 'Meta publishing skipped' } }];
}

const required = ['topic_slug', 'date_key', 'asset_type', 'instagram', 'facebook'];
for (const f of required) {
  if (!asset[f]) {
    throw new Error(`meta_social_asset missing required field: ${f}`);
  }
}

return [{ json: { ...asset, _publish_skip: false } }];

// Expand asset into per-platform publish tasks.
// Each enabled platform produces one 'feed' task and optionally one 'story' task.
const asset = $input.first().json;
const tasks = [];

if (asset.instagram && asset.instagram.enabled) {
  tasks.push({
    platform:  'instagram',
    post_type: 'feed',
    caption:   asset.instagram.caption,
    topic_slug:     asset.topic_slug,
    date_key:       asset.date_key,
    publish_job_id: asset.publish_job_id,
    image_prompt:   asset.ai_output?.image_prompt || null
  });
  if (asset.instagram.story_enabled && asset.instagram.story_caption) {
    tasks.push({
      platform:  'instagram',
      post_type: 'story',
      caption:   asset.instagram.story_caption,
      topic_slug:     asset.topic_slug,
      date_key:       asset.date_key,
      publish_job_id: asset.publish_job_id,
      image_prompt:   asset.ai_output?.story_background_hint || null
    });
  }
}

if (asset.facebook && asset.facebook.enabled) {
  tasks.push({
    platform:  'facebook',
    post_type: 'feed',
    caption:   asset.facebook.caption,
    topic_slug:     asset.topic_slug,
    date_key:       asset.date_key,
    publish_job_id: asset.publish_job_id,
    image_prompt:   asset.ai_output?.image_prompt || null
  });
  if (asset.facebook.story_enabled && asset.facebook.story_caption) {
    tasks.push({
      platform:  'facebook',
      post_type: 'story',
      caption:   asset.facebook.story_caption,
      topic_slug:     asset.topic_slug,
      date_key:       asset.date_key,
      publish_job_id: asset.publish_job_id,
      image_prompt:   asset.ai_output?.story_background_hint || null
    });
  }
}

if (tasks.length === 0) {
  return [{ json: { _publish_skip: true, reason: 'No publish tasks — all platform post types disabled' } }];
}

return tasks.map(t => ({ json: t }));

// Dispatch to the correct Meta Graph API endpoint based on platform.
// Instagram: POST /{ig-user-id}/media  then  POST /{ig-user-id}/media_publish
// Facebook:  POST /{page-id}/feed
//
// This node resolves the API endpoint and credentials for each task.
// Actual HTTP call happens in the next node.
//
// NOTE: Instagram content publishing requires a publishable media URL when
// creating the media container. We resolve that URL from the task payload and
// fail fast if none is available, rather than sending an invalid request.

const task = $input.item.json;

const igUserId  = $vars.META_INSTAGRAM_USER_ID  || null;
const fbPageId  = $vars.META_FACEBOOK_PAGE_ID   || null;
const igToken   = $vars.META_INSTAGRAM_TOKEN     || null;
const fbToken   = $vars.META_FACEBOOK_PAGE_TOKEN || null;

const firstNonEmptyString = (...values) => {
  for (const value of values) {
    if (typeof value === 'string' && value.trim()) {
      return value.trim();
    }
  }
  return null;
};

if (task.platform === 'instagram') {
  if (!igUserId || !igToken) {
    throw new Error('Instagram publishing requires META_INSTAGRAM_USER_ID and META_INSTAGRAM_TOKEN');
  }

  const imageUrl = firstNonEmptyString(
    task.image_url,
    task.asset_url,
    task.media_url,
    task.instagram?.image_url,
    task.instagram?.asset_url,
    task.instagram?.media_url
  );
  const videoUrl = firstNonEmptyString(
    task.video_url,
    task.instagram?.video_url
  );

  if (!imageUrl && !videoUrl) {
    throw new Error('Instagram publishing requires a hosted image_url or video_url on the task payload');
  }

  const isStory = task.post_type === 'story';
  const mediaField = videoUrl
    ? { video_url: videoUrl }
    : { image_url: imageUrl };

  return [{ json: {
    ...task,
    _api_url:    `https://graph.facebook.com/v19.0/${igUserId}/media`,
    _api_method: 'POST',
    _api_token:  igToken,
    _api_body: {
      caption:      task.caption,
      media_type:   isStory ? 'STORIES' : undefined,
      ...mediaField,
      access_token: igToken
    },
    _step: 'create_container'
  } }];
}

if (task.platform === 'facebook') {
  if (!fbPageId || !fbToken) {
    throw new Error('Facebook publishing requires META_FACEBOOK_PAGE_ID and META_FACEBOOK_PAGE_TOKEN');
  }
  const endpoint = task.post_type === 'story'
    ? `https://graph.facebook.com/v19.0/${fbPageId}/photo_stories`
    : `https://graph.facebook.com/v19.0/${fbPageId}/feed`;
  return [{ json: {
    ...task,
    _api_url:    endpoint,
    _api_method: 'POST',
    _api_token:  fbToken,
    _api_body: {
      message:      task.caption,
      access_token: fbToken
    },
    _step: 'publish'
  } }];
}

throw new Error(`Unknown platform: ${task.platform}`);

// Handle Instagram two-step publish: after creating a container, publish it.
// For Facebook feed posts, the response already contains the post ID.
// Errors are captured as failed result items so D1 logging can still run.
const response = $input.item.json;
const task     = $('Resolve API Endpoint').item.json;

// Detect Meta API error — check both response.error and HTTP status codes
const statusCode = response._statusCode || response.statusCode || null;
const hasError = !!response.error || (statusCode && statusCode >= 400);

if (hasError) {
  const errMsg = response.error
    ? `${response.error.message} [code: ${response.error.code}]`
    : `HTTP ${statusCode} — ${JSON.stringify(response).slice(0, 300)}`;
  return [{ json: {
    platform:         task.platform,
    post_type:        task.post_type,
    topic_slug:       task.topic_slug,
    date_key:         task.date_key,
    status:           'failed',
    platform_post_id: null,
    error_message:    errMsg
  } }];
}

// Facebook feed: response.id is the post ID
if (task.platform === 'facebook') {
  return [{ json: {
    platform:         task.platform,
    post_type:        task.post_type,
    topic_slug:       task.topic_slug,
    date_key:         task.date_key,
    status:           'published',
    platform_post_id: response.id || null
  } }];
}

// Instagram: after container creation, publish the container
if (task.platform === 'instagram' && task._step === 'create_container') {
  const containerId = response.id;
  if (!containerId) {
    return [{ json: {
      platform:         task.platform,
      post_type:        task.post_type,
      topic_slug:       task.topic_slug,
      date_key:         task.date_key,
      status:           'failed',
      platform_post_id: null,
      error_message:    `Instagram media container creation did not return an ID. Response: ${JSON.stringify(response).slice(0, 300)}`
    } }];
  }
  const igUserId = $vars.META_INSTAGRAM_USER_ID;
  const igToken  = $vars.META_INSTAGRAM_TOKEN;
  // We need to call the publish endpoint — store container_id for the next HTTP node
  return [{ json: {
    ...task,
    _container_id: containerId,
    _publish_url:  `https://graph.facebook.com/v19.0/${igUserId}/media_publish`,
    _publish_body: { creation_id: containerId, access_token: igToken },
    _step:         'publish_container'
  } }];
}

// Instagram publish step: response.id is the published media ID
return [{ json: {
  platform:         task.platform,
  post_type:        task.post_type,
  topic_slug:       task.topic_slug,
  date_key:         task.date_key,
  status:           'published',
  platform_post_id: response.id || null
} }];

// Extract published media ID from Instagram container publish response.
const response = $input.item.json;
const task     = $('Handle API Response').item.json;

const statusCode = response._statusCode || response.statusCode || null;
const hasError = !!response.error || (statusCode && statusCode >= 400);

if (hasError) {
  const errMsg = response.error
    ? `Instagram container publish error: ${response.error.message} [code: ${response.error.code}]`
    : `Instagram container publish HTTP ${statusCode} — ${JSON.stringify(response).slice(0, 300)}`;
  return [{ json: {
    platform:         'instagram',
    post_type:        task.post_type,
    topic_slug:       task.topic_slug,
    date_key:         task.date_key,
    status:           'failed',
    platform_post_id: null,
    error_message:    errMsg
  } }];
}

return [{ json: {
  platform:         'instagram',
  post_type:        task.post_type,
  topic_slug:       task.topic_slug,
  date_key:         task.date_key,
  status:           'published',
  platform_post_id: response.id || null
} }];

// Collect all publish results and write to D1 meta_social_publish_log.
// Gathers items from both the Facebook/direct-Instagram path and the
// two-step Instagram container publish path.
const results = $input.all().map(i => i.json);
return results.map(r => ({ json: r }));

// Write publish result to D1 meta_social_publish_log.
const r = $input.item.json;
const attempt = Number.isFinite(Number(r.attempt)) ? Number(r.attempt) : 1;
return [{ json: {
  _d1_sql: `INSERT INTO meta_social_publish_log
    (topic_slug, date_key, asset_type, source_type, platform, post_type,
     status, platform_post_id, error_message, attempt, created_at, updated_at)
  VALUES (?, ?, 'daily_post', 'daily_summary', ?, ?, ?, ?, ?, ?,
    strftime('%Y-%m-%dT%H:%M:%SZ','now'),
    strftime('%Y-%m-%dT%H:%M:%SZ','now')
  )`,
  _d1_params: [
    r.topic_slug,
    r.date_key,
    r.platform,
    r.post_type || 'feed',
    r.status || 'published',
    r.platform_post_id || null,
    r.error_message || null,
    attempt
  ],
  ...r,
  attempt
} }];
